export interface ArvoBreadcrumbItem {
  label: string;
  href?: string;
  icon?: string;
}

export interface ArvoBreadcrumbOptions {
  items?: ArvoBreadcrumbItem[];
  separator?: string;
  isDisabled?: boolean;
  isLoading?: boolean;
  ariaLabel?: string;
  onNavigate?: (event: { href: string; index: number; label: string }) => void;
}

type RequiredOptions = Required<Omit<ArvoBreadcrumbOptions, 'onNavigate'>> & {
  onNavigate: ArvoBreadcrumbOptions['onNavigate'] | null;
};

export class ArvoBreadcrumb {
  private _element: HTMLElement | null;
  private _options: RequiredOptions;
  private _listEl: HTMLOListElement | null = null;
  private _originalContent: string;
  private _boundHandleClick: (event: Event) => void;

  static readonly DEFAULTS: RequiredOptions = {
    items: [],
    separator: '/',
    isDisabled: false,
    isLoading: false,
    ariaLabel: 'Breadcrumb',
    onNavigate: null,
  };

  static initialize(element: HTMLElement, options?: ArvoBreadcrumbOptions): ArvoBreadcrumb {
    return new ArvoBreadcrumb(element, options);
  }

  constructor(element: HTMLElement, options?: ArvoBreadcrumbOptions) {
    this._element = element;
    this._originalContent = element.innerHTML;

    this._options = {
      ...ArvoBreadcrumb.DEFAULTS,
      ...options,
      onNavigate: options?.onNavigate ?? null,
    };

    this._boundHandleClick = this._handleClick.bind(this);

    this._render();
    this._bindEvents();
  }

  private _render(): void {
    const el = this._element;
    if (!el) return;

    el.textContent = '';
    el.classList.add('arvo-bc');
    el.setAttribute('aria-label', this._options.ariaLabel);

    this._listEl = document.createElement('ol');
    this._listEl.className = 'arvo-bc__list';
    el.appendChild(this._listEl);

    this._buildItems();

    if (this._options.isDisabled) {
      this._applyDisabled(true);
    }

    if (this._options.isLoading) {
      this._applyLoading(true);
    }
  }

  private _buildItems(): void {
    const list = this._listEl;
    if (!list) return;

    list.textContent = '';
    const items = this._options.items;
    const lastIndex = items.length - 1;

    items.forEach((item, index) => {
      const li = document.createElement('li');
      li.className = 'arvo-bc__item';

      if (index === lastIndex) {
        const span = document.createElement('span');
        span.className = 'arvo-bc__lbl';
        span.setAttribute('aria-current', 'page');
        span.textContent = item.label;
        li.appendChild(span);
      } else {
        const a = document.createElement('a');
        a.className = 'arvo-bc__lnk';
        a.dataset.index = String(index);

        if (item.href && !this._options.isDisabled) {
          a.setAttribute('href', item.href);
        }

        if (this._options.isDisabled) {
          a.setAttribute('aria-disabled', 'true');
          a.setAttribute('tabindex', '0');
        }

        const isIconOnly = !!item.icon && !item.label;

        if (isIconOnly) {
          a.setAttribute('aria-label', 'Home');
        }

        if (item.icon) {
          const ico = document.createElement('span');
          ico.className = `arvo-bc__ico o9con o9con-${item.icon}`;
          ico.setAttribute('aria-hidden', 'true');
          a.appendChild(ico);
        }

        if (item.label) {
          a.appendChild(document.createTextNode(item.label));
        }

        li.appendChild(a);
      }

      list.appendChild(li);
    });
  }

  private _bindEvents(): void {
    this._listEl?.addEventListener('click', this._boundHandleClick);
  }

  private _handleClick(event: Event): void {
    if (this._options.isDisabled || this._options.isLoading) {
      event.preventDefault();
      event.stopPropagation();
      return;
    }

    const target = (event.target as HTMLElement).closest('.arvo-bc__lnk') as HTMLAnchorElement | null;
    if (!target) return;

    const index = Number(target.dataset.index);
    const item = this._options.items[index];
    if (!item) return;

    this._dispatchEvent('bc:navigate', {
      href: item.href ?? '',
      index,
      label: item.label,
    });

    if (this._options.onNavigate && item.href) {
      this._options.onNavigate({
        href: item.href,
        index,
        label: item.label,
      });
    }
  }

  private _dispatchEvent(name: string, detail: Record<string, unknown>): void {
    this._element?.dispatchEvent(new CustomEvent(name, {
      bubbles: true,
      cancelable: true,
      detail,
    }));
  }

  private _applyDisabled(state: boolean): void {
    const el = this._element;
    if (!el) return;

    if (state) {
      el.classList.add('is-disabled');
    } else {
      el.classList.remove('is-disabled');
    }

    const links = el.querySelectorAll<HTMLAnchorElement>('.arvo-bc__lnk');
    links.forEach((link, i) => {
      const item = this._options.items[i];
      if (state) {
        link.setAttribute('aria-disabled', 'true');
        link.removeAttribute('href');
        link.setAttribute('tabindex', '0');
      } else {
        link.removeAttribute('aria-disabled');
        link.removeAttribute('tabindex');
        if (item?.href) {
          link.setAttribute('href', item.href);
        }
      }
    });
  }

  private _applyLoading(isLoading: boolean): void {
    const el = this._element;
    if (!el) return;

    if (isLoading) {
      el.classList.add('loading');
      el.setAttribute('aria-busy', 'true');
    } else {
      el.classList.remove('loading');
      el.removeAttribute('aria-busy');
    }
  }

  setItems(items: ArvoBreadcrumbItem[]): void {
    this._options.items = items;
    this._buildItems();

    if (this._options.isDisabled) {
      this._applyDisabled(true);
    }
  }

  disabled(state?: boolean): boolean | void {
    if (state === undefined) {
      return this._options.isDisabled;
    }

    this._options.isDisabled = state;
    this._applyDisabled(state);
  }

  setLoading(isLoading: boolean): void {
    this._options.isLoading = isLoading;
    this._applyLoading(isLoading);
  }

  destroy(): void {
    const el = this._element;
    if (!el) return;

    this._listEl?.removeEventListener('click', this._boundHandleClick);

    el.classList.remove('arvo-bc', 'is-disabled', 'loading');
    el.removeAttribute('aria-label');
    el.removeAttribute('aria-busy');

    el.innerHTML = this._originalContent;

    this._element = null;
    this._listEl = null;
  }
}
